import React, { useState, useEffect } from 'react';
import './Header.css';

const Header = ({ theme, toggleTheme, language, toggleLanguage }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navItems = [
    { ru: 'Работа', en: 'Work', href: '#research' },
    { ru: 'Проекты', en: 'Projects', href: '#map' },
    { ru: 'О нас', en: 'About', href: '#about' },
    { ru: 'Контакты', en: 'Contacts', href: '#contacts' }
  ];

  const yandexDiskUrl = "https://disk.360.yandex.ru/d/GsTPjQGyMc5ZRw";

  return (
    <header className={`header ${isScrolled ? 'scrolled' : ''}`}>
      <div className="container header-container">
        <a href="/" className="logo">
          <div className="logo-placeholder">
            <div className="logo-wrapper">
              <img 
                src="/images/logo_header.png"
                alt="ТюмГУ" 
              />
            </div>
            <span className="logo-text">ТюмГУ</span>
          </div>
        </a>

        <nav className="nav-desktop">
          {navItems.map((item, index) => (
            <a key={index} href={item.href} className="nav-link">
              {language === 'RU' ? item.ru : item.en}
            </a>
          ))}
        </nav>

        <div className="header-actions">
          <button onClick={toggleLanguage} className="action-btn lang-btn">
            {language}
          </button>
          
          {/* Переключатель темы с двумя иконками */}
          <div className="theme-switch">
            <button 
              onClick={() => theme !== 'light' && toggleTheme()} 
              className={`theme-option ${theme === 'light' ? 'active' : ''}`}
              aria-label="Светлая тема"
            >
              <img 
                src={theme === 'light' ? "/icons/sun-dark.svg" : "/icons/sun-light.svg"}
                alt="Светлая тема" 
                width="18" 
                height="18"
              />
            </button>
            <button 
              onClick={() => theme !== 'dark' && toggleTheme()} 
              className={`theme-option ${theme === 'dark' ? 'active' : ''}`}
              aria-label="Тёмная тема"
            >
              <img 
                src={theme === 'light' ? "/icons/moon-dark.png" : "/icons/moon-light.png"}
                alt="Тёмная тема" 
                width="18" 
                height="18"
              />
            </button>
          </div>

          <a 
            href={yandexDiskUrl} 
            className="action-btn yadisk-btn" 
            target="_blank" 
            rel="noopener noreferrer"
          >
            <img
              src={theme === 'light' ? "/icons/yandex-dark.png" : "/icons/yandex-light.png"}
              alt="Яндекс Диск"
              width="16"
              height="16"
              style={{ marginRight: '6px', verticalAlign: 'middle' }}
            />
            Диск
          </a>
        </div>

        <button className="mobile-menu-btn" onClick={() => setMobileMenuOpen(!mobileMenuOpen)}>
          <span></span>
          <span></span>
          <span></span>
        </button>
      </div>

      <div className={`mobile-nav ${mobileMenuOpen ? 'open' : ''}`}>
        {navItems.map((item, index) => (
          <a key={index} href={item.href} className="mobile-nav-link" onClick={() => setMobileMenuOpen(false)}>
            {language === 'RU' ? item.ru : item.en}
          </a>
        ))}
        <div className="mobile-actions">
          <button onClick={toggleLanguage} className="mobile-action-btn">
            {language}
          </button>
          <div className="mobile-theme-switch">
            <button 
              onClick={() => theme !== 'light' && toggleTheme()} 
              className={`mobile-theme-option ${theme === 'light' ? 'active' : ''}`}
            >
              <img 
                src={theme === 'light' ? "/icons/sun-dark.svg" : "/icons/sun-light.svg"}
                alt="Светлая" 
                width="16" 
                height="16"
              />
              <span>Светлая</span>
            </button>
            <button 
              onClick={() => theme !== 'dark' && toggleTheme()} 
              className={`mobile-theme-option ${theme === 'dark' ? 'active' : ''}`}
            >
              <img 
                src={theme === 'light' ? "/icons/moon-dark.png" : "/icons/moon-light.png"}
                alt="Тёмная" 
                width="16" 
                height="16"
              />
              <span>Тёмная</span>
            </button>
          </div>
          <a 
            href={yandexDiskUrl} 
            className="mobile-action-btn yadisk-mobile-btn" 
            target="_blank" 
            rel="noopener noreferrer"
          >
            <img
              src={theme === 'light' ? "/icons/yandex-dark.png" : "/icons/yandex-light.png"}
              alt="Яндекс Диск"
              width="16"
              height="16"
              style={{ marginRight: '6px', verticalAlign: 'middle' }}
            />
            Диск
          </a>
        </div>
      </div>
    </header>
  );
};

export default Header;