import React, { useEffect, useRef, useState } from 'react';
import './Research.css';
import { AlertTriangle, Rocket } from 'lucide-react';
import AnimatedCounter from './AnimatedCounter';

const Research = ({ language }) => {
  const [barWidths, setBarWidths] = useState([0, 0, 0]);
  const [animateCharts, setAnimateCharts] = useState(false);
  const [animateDonut, setAnimateDonut] = useState(false);
  const sectionRef = useRef(null);

  const content = {
    RU: {
      title: 'Исследование',
      subtitle: 'Опрос 137 иностранных студентов из 14 стран',
      donutTitle: 'Источники информации о Тюмени',
      studentsText: 'студентов',
      hubBefore: 'ДО ПРИЕЗДА',
      hubAfter: 'ПОСЛЕ',
      chartData: [
        { label: 'Ожидания оправдались', value: 80, color: '#2c7da0' },
        { label: 'Сарафанное радио', value: 58.8, color: '#61a5c2' },
        { label: 'Интернет / соцсети', value: 19.5, color: '#89c2d9' }
      ],
      donutLegend: [
        { label: 'Сарафанное радио', value: 58.8, color: '#2c7da0' },
        { label: 'Интернет / соцсети', value: 19.5, color: '#61a5c2' },
        { label: 'Сериалы и фильмы', value: 12.3, color: '#89c2d9' },
        { label: 'Другое', value: 9.4, color: '#a9d6e5' }
      ],
      nodes: [
        { title: 'Суровый холод', desc: '«Страх замерзнуть при -40°C»', color: '#e74c3c', type: 'fear' },
        { title: 'Неадаптация', desc: '«Боязнь не прижиться и остаться чужим»', color: '#f39c12', type: 'fear' },
        { title: 'Документы / Жильё', desc: '«Сложности с оформлением и общежитием»', color: '#e67e22', type: 'fear' },
        { title: 'Неизвестность развеяна', desc: '«Тюмень — это не то, что я думал»', color: '#1abc9c', type: 'reality' },
        { title: 'Современный', desc: '«Красивый центр, ночная красота»', color: '#2980b9', type: 'reality' },
        { title: 'Комфортный ритм', desc: '«Спокойный ритм — по-человечески»', color: '#2ecc71', type: 'reality' }
      ]
    },
    EN: {
      title: 'Research',
      subtitle: 'Survey of 137 international students from 14 countries',
      donutTitle: 'Sources of information about Tyumen',
      studentsText: 'students',
      hubBefore: 'BEFORE ARRIVAL',
      hubAfter: 'AFTER',
      chartData: [
        { label: 'Expectations met', value: 80, color: '#2c7da0' },
        { label: 'Word of mouth', value: 58.8, color: '#61a5c2' },
        { label: 'Internet / Social media', value: 19.5, color: '#89c2d9' }
      ],
      donutLegend: [
        { label: 'Word of mouth', value: 58.8, color: '#2c7da0' },
        { label: 'Internet / Social media', value: 19.5, color: '#61a5c2' },
        { label: 'TV Shows & Movies', value: 12.3, color: '#89c2d9' },
        { label: 'Other', value: 9.4, color: '#a9d6e5' }
      ],
      nodes: [
        { title: 'Severe cold', desc: '"Fear of freezing at -40°C"', color: '#e74c3c', type: 'fear' },
        { title: 'Not adapting', desc: '"Fear of not being accepted"', color: '#f39c12', type: 'fear' },
        { title: 'Dormitory/Docs', desc: '"Bureaucracy and housing concerns"', color: '#e67e22', type: 'fear' },
        { title: 'Unknown Dispersed', desc: '"Tyumen is not what I thought"', color: '#1abc9c', type: 'reality' },
        { title: 'Modern Center', desc: '"Beautiful center, vibrant nightlife"', color: '#2980b9', type: 'reality' },
        { title: 'Comfortable Rhythm', desc: '"Calm rhythm — humane pace"', color: '#2ecc71', type: 'reality' }
      ]
    }
  };

  const data = content[language];

  // Отслеживаем видимость секции и запускаем анимацию
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting) {
          setAnimateCharts(true);
          setAnimateDonut(true);
          observer.disconnect();
        }
      },
      { threshold: 0.1 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => observer.disconnect();
  }, []);

  const handleProgress = (index, value) => {
    setBarWidths(prev => {
      const newWidths = [...prev];
      newWidths[index] = value;
      return newWidths;
    });
  };

  // Анимация круговой диаграммы
  useEffect(() => {
    if (animateDonut) {
      const animateSegments = () => {
        const segments = document.querySelectorAll('.donut-segment');
        const circumference = 502;
        
        segments.forEach(segment => {
          const value = parseFloat(segment.getAttribute('data-value'));
          const dashArray = (value / 100) * circumference;
          segment.style.transition = 'stroke-dasharray 1.5s cubic-bezier(0.4, 0, 0.2, 1)';
          segment.style.strokeDasharray = `${dashArray} ${circumference}`;
        });
      };
      
      animateSegments();
    }
  }, [animateDonut]);

  const totalNodes = 6;
  const width = 850;
  const height = 520; 
  const centerX = 160; 
  const centerY = height / 2; 
  const radius = 175; 
  
  const startAngle = -62 * (Math.PI / 180);
  const endAngle = 62 * (Math.PI / 180);

  const calculatedNodes = data.nodes.map((node, idx) => {
    const angle = startAngle + (idx * (endAngle - startAngle)) / (totalNodes - 1);
    const x = centerX + radius * Math.cos(angle);
    const y = centerY + radius * Math.sin(angle);
    return { ...node, x, y };
  });

  return (
    <section id="research" ref={sectionRef} className="research section">
      <div className="container">
        <h2 className="section-title">{data.title}</h2>
        <p className="section-subtitle">{data.subtitle}</p>

        {/* 1. Горизонтальные прогресс-бары с синхронной анимацией */}
        <div className="charts-container">
          {data.chartData.map((item, idx) => (
            <div key={idx} className="chart-card">
              <div className="chart-header">
                <span className="chart-label">{item.label}</span>
                <span className="chart-percent" style={{ color: item.color }}>
                  <AnimatedCounter 
                    targetValue={item.value} 
                    suffix="%" 
                    duration={1500} 
                    startDelay={idx * 150}
                    onProgress={(progress) => handleProgress(idx, progress)}
                    isActive={animateCharts}
                  />
                </span>
              </div>
              <div className="chart-bar-wrapper">
                <div 
                  className="chart-bar" 
                  style={{ 
                    width: `${barWidths[idx]}%`,
                    backgroundColor: item.color,
                    transition: 'none'
                  }} 
                />
              </div>
            </div>
          ))}
        </div>

        {/* 2. Круговой пончик */}
        <div className="donut-container">
          <h3 className="donut-title">{data.donutTitle}</h3>
          <div className="donut-chart-wrapper">
            <div className="donut-chart">
              <svg viewBox="0 0 200 200" className="donut-svg">
                <circle cx="100" cy="100" r="80" fill="none" stroke="var(--bg-secondary)" strokeWidth="24"/>
                <circle cx="100" cy="100" r="80" fill="none" stroke="#2c7da0" strokeWidth="24" strokeDasharray="0 502" transform="rotate(-90 100 100)" className="donut-segment" data-value="58.8" />
                <circle cx="100" cy="100" r="80" fill="none" stroke="#61a5c2" strokeWidth="24" strokeDasharray="0 502" transform="rotate(-90 100 100)" className="donut-segment" data-value="19.5" />
                <circle cx="100" cy="100" r="80" fill="none" stroke="#89c2d9" strokeWidth="24" strokeDasharray="0 502" transform="rotate(-90 100 100)" className="donut-segment" data-value="12.3" />
                <circle cx="100" cy="100" r="80" fill="none" stroke="#a9d6e5" strokeWidth="24" strokeDasharray="0 502" transform="rotate(-90 100 100)" className="donut-segment" data-value="9.4" />
              </svg>
              <div className="donut-center-text">
                <span className="donut-number">
                  <AnimatedCounter 
                    targetValue={137} 
                    suffix="" 
                    duration={1200} 
                    startDelay={300} 
                    isActive={animateCharts}
                  />
                </span>
                <span className="donut-label">{data.studentsText}</span>
              </div>
            </div>
            <div className="donut-legend">
              {data.donutLegend.map((item, idx) => (
                <div key={idx} className="legend-item">
                  <span className="legend-color" style={{ backgroundColor: item.color }}></span>
                  <span className="legend-text">{item.label} — <strong>{item.value}%</strong></span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* 3. Радиальная инфографика (остаётся без изменений) */}
        <div className="radial-infographic-wrapper">
          <svg viewBox={`0 0 ${width} ${height}`} className="radial-svg">
            <defs>
              <filter id="radial-shadow" x="-10%" y="-10%" width="120%" height="120%">
                <feDropShadow dx="0" dy="3" stdDeviation="4" floodColor="var(--infographic-shadow-color)" floodOpacity="0.15" />
              </filter>
            </defs>

            {calculatedNodes.map((node, idx) => (
              <g key={`line-${idx}`}>
                <line x1={centerX} y1={centerY} x2={node.x} y2={node.y} stroke={node.color} strokeWidth="2.5" />
                <line x1={node.x} y1={node.y} x2={node.x + 30} y2={node.y} stroke={node.color} strokeWidth="2.5" />
              </g>
            ))}

            <circle cx={centerX} cy={centerY} r="105" fill="var(--bg-card)" filter="url(#radial-shadow)" />
            <circle cx={centerX} cy={centerY} r="103" fill="none" stroke="var(--border-color)" strokeWidth="1" />
            <line x1={centerX - 80} y1={centerY} x2={centerX + 80} y2={centerY} stroke="var(--border-color)" strokeWidth="1.5" strokeDasharray="4 4" />

            <text x={centerX} y={centerY - 42} textAnchor="middle" className="hub-title-theme">{data.hubBefore}</text>
            <foreignObject x={centerX - 10} y={centerY - 28} width="20" height="20">
              <div className="hub-icon-theme"><AlertTriangle size={16} strokeWidth={2.5} /></div>
            </foreignObject>

            <foreignObject x={centerX - 10} y={centerY + 12} width="20" height="20">
              <div className="hub-icon-theme"><Rocket size={16} strokeWidth={2.5} /></div>
            </foreignObject>
            <text x={centerX} y={centerY + 48} textAnchor="middle" className="hub-title-theme">{data.hubAfter}</text>

            {calculatedNodes.map((node, idx) => {
              const dotAngle = startAngle + (idx * (endAngle - startAngle)) / (totalNodes - 1);
              const dotX = centerX + 88 * Math.cos(dotAngle);
              const dotY = centerY + 88 * Math.sin(dotAngle);
              return <circle key={`dot-${idx}`} cx={dotX} cy={dotY} r="4.5" fill={node.color} />;
            })}

            {calculatedNodes.map((node, idx) => (
              <g key={`node-dot-${idx}`}>
                <circle cx={node.x} cy={node.y} r="10" fill="var(--bg-card)" stroke={node.color} strokeWidth="3" filter="url(#radial-shadow)" />
                <circle cx={node.x} cy={node.y} r="3.5" fill={node.color} />
              </g>
            ))}

            {calculatedNodes.map((node, idx) => (
              <foreignObject key={`fo-${idx}`} x={node.x + 30} y={node.y - 25} width="430" height="54">
                <div className="radial-card" style={{ borderColor: node.color }}>
                  <div className="radial-card-bullet"></div>
                  <div className="radial-card-body">
                    <h4>{node.title}</h4>
                    <p>{node.desc}</p>
                  </div>
                </div>
              </foreignObject>
            ))}
          </svg>

          <div className="radial-cards-mobile-layer">
            <div className="mobile-sector-divider">
              <AlertTriangle size={14} /> {data.hubBefore}
            </div>
            {data.nodes.filter(n => n.type === 'fear').map((node, idx) => (
              <div key={`mob-f-${idx}`} className="radial-card" style={{ borderColor: node.color }}>
                <div className="radial-card-bullet"></div>
                <div className="radial-card-body">
                  <h4>{node.title}</h4>
                  <p>{node.desc}</p>
                </div>
              </div>
            ))}

            <div className="mobile-sector-divider" style={{ marginTop: '20px' }}>
              <Rocket size={14} /> {data.hubAfter}
            </div>
            {data.nodes.filter(n => n.type === 'reality').map((node, idx) => (
              <div key={`mob-r-${idx}`} className="radial-card" style={{ borderColor: node.color }}>
                <div className="radial-card-bullet"></div>
                <div className="radial-card-body">
                  <h4>{node.title}</h4>
                  <p>{node.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

      </div>
    </section>
  );
};

export default Research;