import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import locations from '../data/locations.json';
import './MapSection.css';

const MapSection = () => {
  const mapRef = useRef(null);
  const mapInstanceRef = useRef(null);

  useEffect(() => {
    if (mapInstanceRef.current) return;

    mapInstanceRef.current = L.map(mapRef.current).setView([57.153, 65.535], 13);
    
    L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
      attribution: '© OpenStreetMap contributors',
      maxZoom: 19,
    }).addTo(mapInstanceRef.current);

    locations.forEach(loc => {
      const marker = L.marker(loc.coords).addTo(mapInstanceRef.current);
      marker.bindPopup(`<b>${loc.icon} ${loc.name}</b><br>${loc.description}`);
    });

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
    };
  }, []);

  const flyToLocation = (coords, name, description) => {
    if (mapInstanceRef.current) {
      mapInstanceRef.current.setView(coords, 16);
      L.popup()
        .setLatLng(coords)
        .setContent(`<b>${name}</b><br>${description}`)
        .openOn(mapInstanceRef.current);
    }
  };

  return (
    <section id="map" className="map-section section">
      <div className="container">
        <h2 className="section-title">Куда пойти в Тюмени?</h2>
        <p className="section-subtitle">10 мест, которые меняют представление о городе</p>
        <div className="map-grid">
          <div ref={mapRef} className="map-wrapper"></div>
          <div className="places-list">
            {locations.map(loc => (
              <div
                key={loc.id}
                className="place-item"
                onClick={() => flyToLocation(loc.coords, `${loc.icon} ${loc.name}`, loc.description)}
              >
                <div className="place-name">{loc.icon} {loc.name}</div>
                <div className="place-desc">{loc.description}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default MapSection;